inSequence.script:
var request = mc.getPayloadJSON();
var missing = [];

function required(name, value) {
    if (value == null || String(value).trim().length === 0) {
        missing.push(name);
    }
}

required('transactionId', request.transactionId);
required('partnerId', request.partnerId);
required('msisdn', request.msisdn);
required('currency', request.currency);
required('expectedCountry', request.expectedCountry);
required('device.latitude', request.device && request.device.latitude);
required('device.longitude', request.device && request.device.longitude);

var amount = Number(request.amount);
if (!Number.isFinite(amount) || amount <= 0) {
    missing.push('amount');
}

var policy = String(request.partialResponsePolicy || 'ALLOW_DEGRADED').toUpperCase();
if (policy !== 'ALLOW_DEGRADED' && policy !== 'FAIL_CLOSED') {
    missing.push('partialResponsePolicy');
}

mc.setProperty('validation.errors', missing.join(', '));
mc.setProperty('request.transactionId', String(request.transactionId || ''));
mc.setProperty('request.partnerId', String(request.partnerId || ''));
mc.setProperty('request.msisdn', String(request.msisdn || ''));
mc.setProperty('request.amount', String(Number.isFinite(amount) ? amount : 0));
mc.setProperty('request.currency', String(request.currency || '').toUpperCase());
mc.setProperty('request.expectedCountry', String(request.expectedCountry || '').toUpperCase());
mc.setProperty('request.latitude', String(request.device && request.device.latitude != null ? Number(request.device.latitude) : 0));
mc.setProperty('request.longitude', String(request.device && request.device.longitude != null ? Number(request.device.longitude) : 0));
mc.setProperty('request.partialResponsePolicy', policy);
mc.setProperty('request.startedAt', String(Date.now()));

then.script:
mc.setPayloadJSON({
    type: 'https://demo.telco/errors/invalid-request',
    title: 'Invalid risk assessment request',
    status: 400,
    detail: 'Missing or invalid fields: ' + String(mc.getProperty('validation.errors')),
    correlationId: String(mc.getProperty('correlation.id') || '')
});

inSequence.script:
function asPlain(value) {
    return JSON.parse(JSON.stringify(value));
}

function flatten(value, output) {
    if (Array.isArray(value)) {
        value.forEach(function (item) { flatten(item, output); });
    } else if (value != null) {
        output.push(value);
    }
}

var raw = asPlain(mc.getPayloadJSON());
var items = [];
flatten(raw, items);

// Some aggregators can wrap the array in a generated property.
if (items.length === 1 && items[0] && Array.isArray(items[0].responses)) {
    items = items[0].responses;
}

var expected = ['crm', 'sim-swap', 'device-location', 'oss'];
var byService = {};
items.forEach(function (item) {
    if (item && item.service) {
        byService[String(item.service)] = item;
    }
});

var unavailable = [];
expected.forEach(function (service) {
    if (!byService[service] || byService[service].status !== 'SUCCESS') {
        unavailable.push(service);
        if (!byService[service]) {
            byService[service] = {
                service: service,
                status: 'UNAVAILABLE',
                error: {
                    code: 'AGGREGATION_TIMEOUT',
                    message: 'No response was received before the aggregation timeout'
                },
                correlationId: String(mc.getProperty('correlation.id') || '')
            };
        }
    }
});

var score = 0;
var reasons = [];
var crm = byService.crm;
var sim = byService['sim-swap'];
var device = byService['device-location'];
var oss = byService.oss;
var amount = Number(mc.getProperty('request.amount') || 0);

if (crm.status === 'SUCCESS') {
    if (crm.data.accountStatus === 'SUSPENDED') {
        score += 55;
        reasons.push('SUBSCRIBER_ACCOUNT_SUSPENDED');
    }
    if (crm.data.fraudWatch === true) {
        score += 35;
        reasons.push('SUBSCRIBER_ON_FRAUD_WATCH');
    }
    if (Number(crm.data.tenureMonths || 0) < 3) {
        score += 10;
        reasons.push('NEW_SUBSCRIBER_ACCOUNT');
    }
} else {
    score += 12;
    reasons.push('CRM_EVIDENCE_UNAVAILABLE');
}

if (sim.status === 'SUCCESS') {
    var swapAge = Number(sim.data.lastSwapAgeHours);
    if (swapAge <= 24) {
        score += 45;
        reasons.push('SIM_SWAP_WITHIN_24_HOURS');
    } else if (swapAge <= 72) {
        score += 30;
        reasons.push('SIM_SWAP_WITHIN_72_HOURS');
    } else if (swapAge <= 168) {
        score += 15;
        reasons.push('SIM_SWAP_WITHIN_7_DAYS');
    }
} else {
    score += 12;
    reasons.push('SIM_SWAP_EVIDENCE_UNAVAILABLE');
}

if (device.status === 'SUCCESS') {
    if (device.data.verified !== true) {
        score += 30;
        reasons.push('DEVICE_LOCATION_NOT_VERIFIED');
    }
    if (device.data.expectedCountry &&
        device.data.networkCountry &&
        device.data.expectedCountry !== device.data.networkCountry) {
        score += 20;
        reasons.push('DEVICE_COUNTRY_MISMATCH');
    }
} else {
    score += 12;
    reasons.push('DEVICE_LOCATION_EVIDENCE_UNAVAILABLE');
}

if (oss.status === 'SUCCESS') {
    if (oss.data.roaming === true) {
        score += 12;
        reasons.push('SUBSCRIBER_ROAMING');
    }
    if (oss.data.networkStatus === 'DEGRADED') {
        score += 10;
        reasons.push('NETWORK_STATUS_DEGRADED');
    }
} else {
    score += 12;
    reasons.push('OSS_EVIDENCE_UNAVAILABLE');
}

if (amount >= 20000) {
    score += 25;
    reasons.push('VERY_HIGH_TRANSACTION_AMOUNT');
} else if (amount >= 5000) {
    score += 10;
    reasons.push('HIGH_TRANSACTION_AMOUNT');
}

score = Math.min(100, score);
var decision = score >= 70 ? 'DENY' : score >= 35 ? 'CHALLENGE' : 'ALLOW';
var policy = String(mc.getProperty('request.partialResponsePolicy') || 'ALLOW_DEGRADED');
var elapsed = Date.now() - Number(mc.getProperty('request.startedAt') || Date.now());

// Critical evidence missing never produces an unconditional ALLOW.
if (unavailable.length > 0 && decision === 'ALLOW') {
    decision = 'CHALLENGE';
    reasons.push('PARTIAL_EVIDENCE_REQUIRES_STEP_UP');
}

if (policy === 'FAIL_CLOSED' && unavailable.length > 0) {
    mc.setProperty('response.http.sc', '503');
    mc.setProperty('response.content.type', 'application/problem+json');
    mc.setPayloadJSON({
        type: 'https://demo.telco/errors/risk-evidence-unavailable',
        title: 'Risk assessment could not be completed',
        status: 503,
        detail: 'One or more required evidence services were unavailable and FAIL_CLOSED was requested.',
        transactionId: String(mc.getProperty('request.transactionId') || ''),
        unavailableServices: unavailable,
        evidence: expected.map(function (service) { return byService[service]; }),
        correlationId: String(mc.getProperty('correlation.id') || ''),
        processingTimeMs: elapsed
    });
} else {
    mc.setProperty('response.http.sc', '200');
    mc.setProperty('response.content.type', 'application/json');
    mc.setPayloadJSON({
        transactionId: String(mc.getProperty('request.transactionId') || ''),
        partnerId: String(mc.getProperty('request.partnerId') || ''),
        decision: decision,
        riskScore: score,
        reasons: reasons,
        partialResponse: unavailable.length > 0,
        partialResponsePolicy: policy,
        unavailableServices: unavailable,
        evidence: expected.map(function (service) { return byService[service]; }),
        correlationId: String(mc.getProperty('correlation.id') || ''),
        processingTimeMs: elapsed
    });
}
